const items = $input.all();

const realItems = items.filter((i) => i?.json && Object.keys(i.json).length > 0 && i.json.id);

let maxVideoNumber = 0;
const usedReferenceIds = new Set();

for (const item of realItems) {
  const name = String(item?.json?.name || '');
  const numMatch = name.match(/video_(\d+)/i);
  if (numMatch) {
    const n = Number(numMatch[1]);
    if (Number.isFinite(n) && n > maxVideoNumber) maxVideoNumber = n;
  }

  const refMatch = name.match(/__ref_([a-z0-9_]+)/i);
  if (refMatch) usedReferenceIds.add(refMatch[1].toLowerCase());
}

const nextVideoNumber = maxVideoNumber + 1;

return [{
  json: {
    totalVideosTracked: realItems.length,
    nextVideoNumber,
    usedReferenceIds: Array.from(usedReferenceIds)
  }
}];

const chapterItems = $input.all();
const normalizeNode = $item(0).$node['Normalize Count'].json;
const usedReferenceIds = new Set((normalizeNode.usedReferenceIds || []).map((x) => String(x).toLowerCase()));

const PER_RUN = Number(chapterItems[0]?.json?.perRun || 10);

const slugBook = (name) => String(name || '').toLowerCase().replace(/[^a-z0-9]+/g, '');
const cleanText = (t) => String(t || '').replace(/\s+/g, ' ').trim();

const verseCandidates = [];
const seen = new Set();

for (const item of chapterItems) {
  const j = item.json || {};
  const verses = Array.isArray(j.verses) ? j.verses : [];

  for (const v of verses) {
    const book = String(v.book_name || '').trim();
    const chapter = Number(v.chapter);
    const verse = Number(v.verse);
    const text = cleanText(v.text || '');

    if (!book || !Number.isFinite(chapter) || !Number.isFinite(verse) || !text) continue;

    const referenceId = `${slugBook(book)}_${chapter}_${verse}`;
    if (usedReferenceIds.has(referenceId) || seen.has(referenceId)) continue;

    seen.add(referenceId);
    verseCandidates.push({
      verse: text,
      reference: `${book} ${chapter}:${verse}`,
      referenceId
    });
  }
}

if (verseCandidates.length < PER_RUN) {
  throw new Error(`Need ${PER_RUN} unused verses, but only found ${verseCandidates.length} from chapter candidates.`);
}

for (let i = verseCandidates.length - 1; i > 0; i--) {
  const j = Math.floor(Math.random() * (i + 1));
  [verseCandidates[i], verseCandidates[j]] = [verseCandidates[j], verseCandidates[i]];
}

const baseVideoNumber = Number(normalizeNode.nextVideoNumber || 1);
const selected = verseCandidates.slice(0, PER_RUN);

return selected.map((s, idx) => {
  const nextVideoNumber = baseVideoNumber + idx;
  const drive_name = `video_${nextVideoNumber}__ref_${s.referenceId}.mp4`;

  const now = new Date();
  const stamp = now.toISOString().replace(/[-:TZ.]/g, '').slice(0, 14);
  const output_name = `bible_short_${stamp}_${idx}.mp4`;

  return {
    json: {
      verse: s.verse,
      reference: s.reference,
      referenceId: s.referenceId,
      output_name,
      drive_name,
      duration: 11,
      driveQueueFolderPath: 'BibleShorts/queue',
      emailTo: String($env.NOTIFY_EMAIL_TO || '')
    }
  };
});

const uploaded = $json;
const driveName = uploaded.name || $item(0).$node['Build Render Payload'].json.drive_name;
const queueCount = Number($item(0).$node['Normalize Count'].json.nextVideoNumber || 0);

return [{
  json: {
    filename: driveName,
    queueCount,
    folderPath: $item(0).$node['Build Render Payload'].json.driveQueueFolderPath,
    emailTo: $item(0).$node['Build Render Payload'].json.emailTo,
    reference: $item(0).$node['Build Render Payload'].json.reference
  }
}];
